package com.csj.archive.logistics.runtime;
import com.csj.archive.logistics.common.ApiResponse; import org.springframework.data.domain.PageRequest; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/runtime-outbound") public class ArchiveOsRuntimeOutboundController {
 private final ArchiveOsRuntimeDeliveryRepository repo; private final ArchiveOsRuntimeProperties props;
 public ArchiveOsRuntimeOutboundController(ArchiveOsRuntimeDeliveryRepository repo,ArchiveOsRuntimeProperties props){this.repo=repo;this.props=props;}
 @GetMapping("/summary") public ApiResponse<Map<String,Object>> summary(){Map<String,Object> r=new LinkedHashMap<>();r.put("total",repo.count());for(ArchiveOsDeliveryStatus s:ArchiveOsDeliveryStatus.values())r.put(camel(s),repo.countByStatus(s));r.put("runtimeIngestEnabled",props.isEnabled());r.put("schedulerEnabled",props.isSchedulerEnabled());return ApiResponse.ok(r);}
 @GetMapping("/events") public ApiResponse<List<Map<String,Object>>> events(@RequestParam(required=false) ArchiveOsDeliveryStatus status,@RequestParam(required=false) String correlationId,@RequestParam(defaultValue="50") int limit){int size=Math.max(1,Math.min(200,limit));List<ArchiveOsRuntimeDeliveryEntity> values=correlationId!=null?repo.findByCorrelationId(correlationId,PageRequest.of(0,size)):status!=null?repo.findByStatus(status,PageRequest.of(0,size)):repo.findAll(PageRequest.of(0,size)).getContent();return ApiResponse.ok(values.stream().map(this::view).toList());}
 @GetMapping("/correlation/{correlationId}/preview") public ApiResponse<Map<String,Object>> preview(@PathVariable String correlationId){List<ArchiveOsRuntimeDeliveryEntity> v=repo.findByCorrelationId(correlationId);Map<String,Object> r=new LinkedHashMap<>();r.put("correlationId",correlationId);r.put("totalEvents",v.size());r.put("rootEvents",v.stream().filter(x->x.payload().path("causationId").isNull()).count());r.put("eventsWithOrderId",v.stream().filter(x->!x.payload().path("orderId").isNull()).count());r.put("eventsWithoutOrderId",v.stream().filter(x->x.payload().path("orderId").isNull()).count());for(ArchiveOsDeliveryStatus s:ArchiveOsDeliveryStatus.values())r.put(camel(s),v.stream().filter(x->x.status()==s).count());r.put("alreadyDelivered",v.stream().filter(x->x.status()==ArchiveOsDeliveryStatus.PUBLISHED).count());return ApiResponse.ok(r);}
 private Map<String,Object> view(ArchiveOsRuntimeDeliveryEntity e){Map<String,Object> r=new LinkedHashMap<>();r.put("eventId",e.eventId());r.put("correlationId",e.correlationId());r.put("status",e.status());r.put("retryCount",e.retryCount());return r;} private String camel(ArchiveOsDeliveryStatus s){String[] p=s.name().toLowerCase().split("_");StringBuilder b=new StringBuilder(p[0]);for(int i=1;i<p.length;i++)b.append(Character.toUpperCase(p[i].charAt(0))).append(p[i].substring(1));return b.toString();}
}
